# Quick lookup helpers
def get_vendors():
    return sorted(set(ap['vendor'] for ap in AP_MODELS))

def get_models_by_vendor(vendor):
    return [ap for ap in AP_MODELS if ap['vendor'].lower() == vendor.lower()]

def get_model(vendor, model):
    for ap in AP_MODELS:
        if ap['vendor'].lower() == vendor.lower() and ap['model'].lower() == model.lower():
            return ap
    return None

def search_models(query):
    q = query.lower()
    results = []
    for ap in AP_MODELS:
        searchable = f"{ap['vendor']} {ap['model']} {ap['series']} {ap['wifi_gen']} {ap['standard']} {ap['bands']} {ap.get('notes', '')}".lower()
        if q in searchable:
            results.append(ap)
    return results

def get_wifi_gen_summary():
    gens = {}
    for ap in AP_MODELS:
        g = ap['wifi_gen']
        gens.setdefault(g, 0)
        gens[g] += 1
    return gens
